#!/usr/bin/env node
// scaffold-day4.mjs - Day 4: CEO-in-the-loop (DM inbox + reply)
//
// Adds:
//   1. Inbox tab in dashboard - shows DMs to the CEO sentinel
//   2. Reply form for each DM (text input, sends via POST /api/dm/send)
//   3. "Send a new DM" panel - DM any of the 12 agents directly
//   4. Agents see their unread DMs in their next ritual cycle (chatter, standup, ceo-brief)
//   5. Eleanor's CEO Brief now factors in company-wide DM activity
//
// Reply latency model: agents read DMs on their next ritual run.
// At 60x speed that is roughly 1 wall minute.
//
// Touches the database with one tiny migration (just an index).
// Does NOT touch runner.ts.
//
// PREREQUISITE - run this SQL in Supabase SQL editor BEFORE running the scaffold:
//
//   create index if not exists dms_unread_idx
//     on dms(to_id, created_at desc)
//     where read_at is null;
//
// (This is the migration from 0005_day4.sql.)

import { mkdirSync, writeFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';

const ROOT = process.cwd();

function writeFile(relPath, base64Content) {
  const full = resolve(ROOT, relPath);
  mkdirSync(dirname(full), { recursive: true });
  writeFileSync(full, Buffer.from(base64Content, 'base64'));
  console.log('  + ' + relPath);
}

console.log('');
console.log('Day 4 scaffold - CEO-in-the-loop (DM inbox + reply)');
console.log('Writing to: ' + ROOT);
console.log('');
console.log('Writing 7 files...');

writeFile('apps/dashboard/app/api/dm/send/route.ts', '');
writeFile('apps/dashboard/app/page.tsx', '');
writeFile('apps/orchestrator/src/comms/dm.ts', '');
writeFile('apps/orchestrator/src/rituals/ceo-brief.ts', '');
writeFile('apps/orchestrator/src/rituals/chatter.ts', '');
writeFile('apps/orchestrator/src/rituals/standup.ts', '');
writeFile('apps/orchestrator/supabase/migrations/0005_day4.sql', '');

console.log('');
console.log('Done. Wrote 7 files.');
console.log('');
console.log('==========================================');
console.log('NEXT STEPS - do these in order:');
console.log('==========================================');
console.log('');
console.log('1. Run the SQL migration in Supabase SQL editor:');
console.log('');
console.log('   create index if not exists dms_unread_idx');
console.log('     on dms(to_id, created_at desc)');
console.log('     where read_at is null;');
console.log('');
console.log('2. Verify the index landed:');
console.log('');
console.log("   select indexname from pg_indexes where indexname = 'dms_unread_idx';");
console.log('');
console.log('3. Restart the orchestrator (Terminal A):');
console.log('   Ctrl+C, then: pnpm orchestrator:dev');
console.log('');
console.log('4. Restart the dashboard (Terminal B):');
console.log('   Ctrl+C, then: pnpm dashboard:dev');
console.log('');
console.log('5. Open dashboard, click the new // INBOX tab. Type a message to any agent.');
console.log('   Within 1 wall minute their next ritual run will read it.');
console.log('');
console.log('VERIFY:');
console.log('  - Inbox tab visible in dashboard');
console.log('  - Click any agent name to compose, type, send');
console.log('  - Check Terminal A: next chatter or standup cycle should run normally');
console.log('  - The recipient agents next post should reference your message');
console.log('  - Eleanors next CEO Brief should mention DM activity in the today line');
console.log('');
